import { useState , useEffect} from 'react';
import './App.css';


const App = () => {
  let i = "hello world";
  let [cnt , setCnt] = useState(0);
  useEffect(() => {

  },[cnt])
  return(
    <div className="App">
      <h1>
        <button onClick={()=> setCnt(++cnt)} >+</button><br></br>
        <>
          <h1>{i}</h1>
          <br></br>
        </>
        <button onClick={()=> setCnt(--cnt)} >-</button><br></br>
      </h1>
    </div>
  )
}

export default App;
